function BrandPanel({ name }: { name?: string }) {
  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        width: 480,
        height: 630,
        backgroundColor: INK,
        padding: "52px 48px",
        justifyContent: "space-between",
        flexShrink: 0,
      }}
    >
      {/* Logo chip */}
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <svg width="44" height="44" viewBox="0 0 1024 1024">
          <path fill="white" d={LOGO_PATH} />
        </svg>
        <span
          style={{
            color: "white",
            fontSize: 26,
            fontWeight: 700,
            letterSpacing: -0.5,
          }}
        >
          viewpet
        </span>
      </div>

      {/* Pet name */}
      {name && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <span
            style={{
              color: MUTED,
              fontSize: 18,
              letterSpacing: 4,
              textTransform: "uppercase",
            }}
          >
            Conheça
          </span>
          <span
            style={{
              color: "white",
              fontSize: 72,
              fontWeight: 800,
              lineHeight: 1,
              letterSpacing: -2,
            }}
          >
            {name}
          </span>
        </div>
      )}

      {/* Footer */}
      <span style={{ color: MUTED, fontSize: 16 }}>viewpet.com</span>
    </div>
  );
}

export default async function OGImage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const entry = await getPetEntry(id);

  // Fallback: brand-only card for missing/empty pets
  if (entry.status !== "filled") {
    return new ImageResponse(
      <div
        style={{
          display: "flex",
          width: 1200,
          height: 630,
          backgroundColor: INK,
          alignItems: "center",
          justifyContent: "center",
          gap: 24,
        }}
      >
        <svg width="120" height="120" viewBox="0 0 1024 1024">
          <path fill="white" d={LOGO_PATH} />
        </svg>
        <span style={{ color: "white", fontSize: 64, fontWeight: 700 }}>
          viewpet
        </span>
      </div>,
      { ...size },
    );
  }

  const pet = entry.pet;

  // Resolve relative upload paths to absolute URLs
  const headersList = await headers();
  const host = headersList.get("host") ?? "localhost:3000";
  const protocol = host.startsWith("localhost") ? "http" : "https";
  const baseUrl = `${protocol}://${host}`;
  const pictureUrl = pet.pictureUrl.startsWith("http")
    ? pet.pictureUrl
    : `${baseUrl}${pet.pictureUrl}`;

  return new ImageResponse(
    <div style={{ display: "flex", width: 1200, height: 630 }}>
      <BrandPanel name={pet.name} />

      {/* Pet photo — fills remaining width */}
      <div style={{ display: "flex", flex: 1, overflow: "hidden" }}>
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img
          src={pictureUrl}
          alt={pet.name}
          width={720}
          height={630}
          style={{ width: 720, height: 630, objectFit: "cover" }}
        />
      </div>
    </div>,
    { ...size },
  );
}
